import Foundation

func solve(nums: [Int64], queries: [[Int64]]) -> Int64 {
    let MOD: Int64 = 1000000007
    let maxv = 100000
    var inv_arr = [Int64](repeating: 0, count: maxv+1)
    if maxv >= 1 {
        inv_arr[1] = 1
    }
    if maxv >= 2 {
        for i in 2...maxv {
            let i64 = Int64(i)
            let r_val = MOD % i64
            let q_val = MOD / i64
            let term = q_val * inv_arr[Int(r_val)] % MOD
            inv_arr[i] = (MOD - term) % MOD
        }
    }

    let n = nums.count
    let T = Int(sqrt(Double(n))) + 1
    let T_int64 = Int64(T)

    var factor = [Int64](repeating: 1, count: n)
    var queries_by_k = [[(l: Int64, r: Int64, v: Int64)]](repeating: [], count: T+1)

    for query in queries {
        let l = query[0]
        let r_bound = query[1]
        let k_val = query[2]
        let v_val = query[3]

        if k_val > T_int64 {
            var idx = l
            while idx <= r_bound {
                let idx_int = Int(idx)
                factor[idx_int] = (factor[idx_int] * v_val) % MOD
                idx += k_val
            }
        } else {
            let k_index = Int(k_val)
            if k_index >= 1 && k_index <= T {
                queries_by_k[k_index].append((l, r_bound, v_val))
            }
        }
    }

    for k in 1...T {
        var residue_queries = Array(repeating: [(j0: Int, j_max: Int, v: Int64)](), count: k)

        for (l, r_bound, v_val) in queries_by_k[k] {
            let residue = Int(l % Int64(k))
            let residue_value = Int64(residue)
            if l < residue_value {
                continue
            }
            let j0 = (l - residue_value) / Int64(k)
            if j0 < 0 {
                continue
            }
            if r_bound < residue_value {
                continue
            }
            let j_max = (r_bound - residue_value) / Int64(k)
            if j_max < j0 {
                continue
            }
            residue_queries[residue].append((Int(j0), Int(j_max), v_val))
        }

        for r in 0..<k {
            if r >= n {
                continue
            }
            let L = (n - 1 - r) / k + 1
            var diff = [Int64](repeating: 1, count: L+1)

            for (j0, j_max, v_val) in residue_queries[r] {
                if j0 < L {
                    diff[j0] = (diff[j0] * v_val) % MOD
                }
                if j_max + 1 < L {
                    diff[j_max+1] = (diff[j_max+1] * inv_arr[Int(v_val)]) % MOD
                }
            }

            var current: Int64 = 1
            for j in 0..<L {
                current = (current * diff[j]) % MOD
                let idx = r + j * k
                if idx < n {
                    factor[idx] = (factor[idx] * current) % MOD
                }
            }
        }
    }

    var result_nums = nums
    for i in 0..<n {
        result_nums[i] = (result_nums[i] * factor[i]) % MOD
    }

    var xor_result: Int64 = 0
    for num in result_nums {
        xor_result ^= num
    }

    return xor_result
}
