import Foundation

func solve(nums: Array<Int64>, queries: Array<Array<Int64>>) -> Int64 {
    let mod_val: Int64 = 1000000007
    let n = nums.count
    if n == 0 { return 0 }
    let sqrt_n = Int(sqrt(Double(n)))

    func power(_ base: Int64, _ exponent: Int64, _ mod: Int64) -> Int64 {
        var result: Int64 = 1
        var base = base % mod
        var exponent = exponent
        while exponent > 0 {
            if exponent & 1 == 1 {
                result = (result * base) % mod
            }
            base = (base * base) % mod
            exponent /= 2
        }
        return result
    }

    func mod_inv(_ x: Int64, _ mod: Int64) -> Int64 {
        return power(x, mod-2, mod)
    }

    var ans = nums

    if n == 0 {
        return 0
    }

    var buffer = [[[(Int64, Int64, Int64)]]](repeating: [], count: sqrt_n+1)
    for k in 1...sqrt_n {
        buffer[k] = Array(repeating: [], count: k)
    }

    for query in queries {
        let l = query[0]
        let r = query[1]
        let k_val = query[2]
        let v = query[3]

        if k_val > Int64(sqrt_n) {
            var idx = l
            while idx <= r {
                ans[Int(idx)] = (ans[Int(idx)] * v) % mod_val
                idx += k_val
            }
        } else {
            let kk = Int(k_val)
            let residue = Int(l % k_val)
            if kk < buffer.count && residue < buffer[kk].count {
                buffer[kk][residue].append((l, r, v))
            }
        }
    }

    for k in 1...sqrt_n {
        for residue in 0..<k {
            let queries_list = buffer[k][residue]
            if queries_list.isEmpty {
                continue
            }

            let residue_i64 = Int64(residue)
            let k_i64 = Int64(k)
            var A: [Int64] = []
            var current = residue_i64
            while current < Int64(n) {
                A.append(current)
                current += k_i64
            }
            let m = A.count
            if m == 0 {
                continue
            }

            var events = [Int64](repeating: 1, count: m+1)

            for (l, r, v) in queries_list {
                var low_bound: Int? = nil
                var low = 0
                var high = m - 1
                while low <= high {
                    let mid = (low + high) / 2
                    if A[mid] >= l {
                        low_bound = mid
                        high = mid - 1
                    } else {
                        low = mid + 1
                    }
                }
                guard let L_index = low_bound else {
                    continue
                }

                var high_bound: Int? = nil
                low = 0
                high = m - 1
                while low <= high {
                    let mid = (low + high) / 2
                    if A[mid] <= r {
                        high_bound = mid
                        low = mid + 1
                    } else {
                        high = mid - 1
                    }
                }
                guard let R_index = high_bound, R_index >= L_index else {
                    continue
                }

                events[L_index] = (events[L_index] * v) % mod_val
                if R_index + 1 <= m {
                    events[R_index + 1] = (events[R_index + 1] * mod_inv(v, mod_val)) % mod_val
                }
            }

            var currentFactor: Int64 = 1
            for j in 0..<m {
                currentFactor = (currentFactor * events[j]) % mod_val
                let index_in_arr = Int(A[j])
                ans[index_in_arr] = (ans[index_in_arr] * currentFactor) % mod_val
            }
        }
    }

    var result: Int64 = 0
    for num in ans {
        result ^= num
    }

    return result
}
